// src/components/StyleEditor/StyleEditor.jsx
import React from 'react';

const StyleEditor = ({ conferenceId, onSave, onClose, embedded = false }) => {
  console.log('🎨 StyleEditor рендерится!', { conferenceId, embedded });
  
  return (
    <div style={{
      position: 'fixed',
      top: '50%',
      left: '50%',
      transform: 'translate(-50%, -50%)',
      backgroundColor: 'white',
      padding: '30px',
      borderRadius: '10px',
      boxShadow: '0 0 100px rgba(0,0,0,0.5)',
      zIndex: 99999,
      minWidth: '400px',
      border: '3px solid red'
    }}>
      <h2>🎨 ТЕСТОВЫЙ StyleEditor</h2>
      <p>ID конференции: {conferenceId}</p>
      <p>Embedded режим: {embedded ? 'Да' : 'Нет'}</p>
      <div style={{ marginTop: '20px', display: 'flex', gap: '10px' }}>
        <button onClick={onClose}>Закрыть</button>
        <button onClick={onSave}>Сохранить</button>
      </div>
    </div>
  );
};

export default StyleEditor;
